use Illuminate\Http\Request;
use Illuminate\Support\Facades\DB;

class ProductController extends Controller
{
    public function searchProducts(Request $request)
    {
        $baseQuery = "SELECT * FROM products";
        $conditions = [];
        $bindings = [];

        if ($request->filled('name')) {
            $conditions[] = "name LIKE ?";
            $bindings[] = '%' . $request->input('name') . '%';
        }

        if ($request->filled('category')) {
            // Assuming 'category_id' is the column name for category filtering
            $conditions[] = "category_id = ?";
            $bindings[] = $request->input('category');
        }

        if ($request->filled('min_price')) {
            $conditions[] = "price >= ?";
            $bindings[] = $request->input('min_price');
        }

        if ($request->filled('max_price')) {
            $conditions[] = "price <= ?";
            $bindings[] = $request->input('max_price');
        }

        if (!empty($conditions)) {
            $baseQuery .= " WHERE " . implode(" AND ", $conditions);
        }

        // Add ordering, limits, or pagination if needed for flexibility
        // Example: $baseQuery .= " ORDER BY price ASC LIMIT 10 OFFSET 0";

        $products = DB::select(DB::raw($baseQuery), $bindings);

        return response()->json($products);
    }
